INSERT INTO indicator_observations (indicator_id, observed_at, value, source_id, payload_hash) VALUES ('smr_programme', '2026-04-16T14:02:00.000Z', 62.6493, 'gov_uk', 'seed_smr_programme_h1');
INSERT INTO delivery_commitments (id, name, department, latest, target, status, source_url, source_label, notes, updated_at, sort_order) VALUES ('housing_305k', 'Net housing additions toward 305k/year by 2030/31', 'MHCLG', 'Live indicator: Q4 2025 completions × 4 = 146,880 vs 300k OBR working assumption (49%). Annual NAD FY24/25: 221,400 vs 305k Labour target (73%).', 'OBR path: 305k by 2030/31', 'slipping', 'https://www.gov.uk/government/statistical-data-sets/live-tables-on-house-building', 'MHCLG live tables', 'Two complementary measures of housing delivery. (1) The live indicator uses ''Completions, seasonally adjusted'' from the MHCLG Housing supply quarterly release — a quarterly cadence we annualise (×4) and compare against the 300,000-per-year OBR working assumption documented in the EFO supplementary tables. (2) The annual headline figure is ''Net additional dwellings'' from MHCLG Live Tables 211, a broader measure that includes change-of-use and conversions, published once a year (FY24/25 was 221,400). The 305k-by-2030/31 path target is the Labour government''s headline pledge; OBR''s 300k working assumption is what the live indicator benchmarks against to keep continuity with pre-Labour trajectory analysis. Showing both because they tell the same story at different sampling rates and at slightly different scope.', '2026-04-27T12:00:00.000Z', 10);
INSERT INTO delivery_commitments (id, name, department, latest, target, status, source_url, source_label, notes, updated_at, sort_order) VALUES ('new_towns', 'Seven new towns -- designation and first spade', 'DLUHC', '3 of 7 designated, 0 of 7 first-spade', 'Target: all designated 2026', 'on_track', 'https://www.gov.uk/government/groups/the-new-towns-taskforce', 'New Towns Taskforce', 'Taskforce interim report and designations list. First-spade status is tracked in quarterly DLUHC progress updates; we count only sites with confirmed development consent orders.', '2026-04-17T14:02:00.000Z', 20);
INSERT INTO delivery_commitments (id, name, department, latest, target, status, source_url, source_label, notes, updated_at, sort_order) VALUES ('bics_rollout', 'British Industrial Competitiveness Scheme rollout', 'DESNZ', '8,140 firms onboarded, target >10,000 by Apr 2027', 'Up to 25% electricity relief', 'on_track', 'https://www.gov.uk/government/organisations/department-for-energy-security-and-net-zero', 'DESNZ (scheme page)', 'Onboarded-firms count from DESNZ monthly BICS update letters and quarterly ministerial statements to the House. There is no single machine-readable dashboard yet; see the DESNZ homepage for the latest statement.', '2026-04-17T14:02:00.000Z', 30);
INSERT INTO delivery_commitments (id, name, department, latest, target, status, source_url, source_label, notes, updated_at, sort_order) VALUES ('smr_fleet', 'Small Modular Reactor fleet, first site selected', 'GBE', 'Shortlist of 3 sites, final FID slipped to Q3', 'Original target: Q1 2026', 'slipping', 'https://www.gov.uk/government/organisations/great-british-energy', 'Great British Energy', 'Site shortlist and FID dates tracked via Great British Nuclear ministerial updates. Latest status is the most recent SMR programme announcement on the GBE page.', '2026-04-17T14:02:00.000Z', 40);
INSERT INTO delivery_commitments (id, name, department, latest, target, status, source_url, source_label, notes, updated_at, sort_order) VALUES ('planning_bill', 'Planning and Infrastructure Bill -- Royal Assent', 'Parliament', 'Received Royal Assent 18 Dec 2025', 'Commitment delivered', 'shipped', 'https://www.legislation.gov.uk/ukpga/2025/34/enacted', 'Planning & Infrastructure Act 2025', 'Full enacted text on legislation.gov.uk. Stage-by-stage parliamentary record at bills.parliament.uk/bills/3946. Royal Assent 18 December 2025.', '2026-04-17T14:02:00.000Z', 50);
INSERT INTO delivery_commitments (id, name, department, latest, target, status, source_url, source_label, notes, updated_at, sort_order) VALUES ('keep_britain_working', 'Keep Britain Working -- health-related inactivity', 'DWP', '2.81m, effectively unchanged from 2.80m at launch', 'Stated ambition: meaningful reduction by 2027', 'missed', 'https://www.gov.uk/government/organisations/department-for-work-pensions', 'DWP', 'Inactivity-due-to-long-term-sickness numbers come from ONS Labour Force Survey (series LF69, LFS: Econ. inactivity reasons: Long Term Sick: UK: 16-64). The policy target is set out in the DWP ''Get Britain Working'' white paper; the rolling figure is against that baseline.', '2026-04-17T14:02:00.000Z', 60);
INSERT INTO delivery_commitments (id, name, department, latest, target, status, source_url, source_label, notes, updated_at, sort_order) VALUES ('sizewell_c', 'Sizewell C -- construction milestones', 'DESNZ', 'Main civils underway, on schedule vs. 2024 baseline', 'Commissioning late 2030s', 'on_track', 'https://www.sizewellc.com/', 'Sizewell C project', 'Milestone status from the project''s quarterly updates. Spending profile cross-referenced against DESNZ annual report and OBR EFO Box on NPP programme costs.', '2026-04-17T14:02:00.000Z', 70);
INSERT INTO delivery_commitments (id, name, department, latest, target, status, source_url, source_label, notes, updated_at, sort_order) VALUES ('grid_connections', 'Grid connections reform -- queue reduction', 'DESNZ/NESO', 'Queue re-ordered, first cohort through in Q1', 'End "first come first served" by 2026', 'on_track', 'https://www.neso.energy/', 'NESO (connections reform)', 'Queue-reform progress comes from NESO''s Connections Reform programme updates. Confirm via the most recent TMO4+ milestone report on the NESO site.', '2026-04-17T14:02:00.000Z', 80);
INSERT INTO timeline_events (id, event_date, title, summary, category, source_label, source_url) VALUES ('t_2026_04_22', '2026-04-22', 'March CPI rises to 3.3%, BoE path under scrutiny', 'ONS releases March 2026 CPI inflation data showing headline CPI at 3.3% YoY (up from ~3.0% in February), driven by lingering energy and petrol price effects from the Iran conflict period. Markets price in a more cautious BoE path ahead of the 30 April MPC decision; gilt yields stabilise but remain elevated.', 'fiscal', 'ONS Consumer price inflation', 'https://www.ons.gov.uk/economy/inflationandpriceindices/bulletins/consumerpriceinflation/latest');
INSERT INTO timeline_events (id, event_date, title, summary, category, source_label, source_url) VALUES ('t_2026_04_21', '2026-04-21', 'Resolution Foundation: conflict could erase £16bn of headroom', 'Resolution Foundation warns that a prolonged or severe Middle East conflict could erase up to £16bn of the Chancellor''s current-budget headroom — almost three-quarters of the March OBR cushion — via higher energy prices, inflation, and debt interest. Report highlights fiscal vulnerability even under the current ceasefire.', 'fiscal', 'Resolution Foundation', 'https://www.resolutionfoundation.org/publications/');
INSERT INTO timeline_events (id, event_date, title, summary, category, source_label, source_url) VALUES ('t_2026_04_08', '2026-04-08', 'US, Israel and Iran agree conditional ceasefire', 'US, Israel and Iran agree a conditional two-week ceasefire; UK Foreign Secretary and international finance ministers welcome the de-escalation, citing restored Strait of Hormuz shipping and falling oil and gas prices. Initial market relief begins, setting the stage for sterling''s recovery to pre-war levels by 17 April.', 'geopolitical', 'Foreign Office / gov.uk', 'https://www.gov.uk/government/organisations/foreign-commonwealth-development-office');
INSERT INTO timeline_events (id, event_date, title, summary, category, source_label, source_url) VALUES ('t_2026_04_17', '2026-04-17', 'Sterling recovers to pre-war levels', 'GBP/USD back near 1.2400 as the Iran ceasefire holds and Strait of Hormuz shipping normalises. Oil and UK gas sell off sharply. BoE officials nonetheless stress inflation control remains the priority.', 'market', 'Bank of England exchange rates', 'https://www.bankofengland.co.uk/statistics/exchange-rates');
INSERT INTO timeline_events (id, event_date, title, summary, category, source_label, source_url) VALUES ('t_2026_04_16', '2026-04-16', 'Reeves rules out tax rises or borrowing for extra defence spending', 'Chancellor tells reporters additional defence outlays up to the 3.5% commitment will not be funded by more borrowing or higher taxes, pointing the pressure back at welfare and departmental restraint.', 'fiscal', 'HM Treasury news', 'https://www.gov.uk/government/organisations/hm-treasury');
INSERT INTO timeline_events (id, event_date, title, summary, category, source_label, source_url) VALUES ('t_2026_03_03', '2026-03-03', 'OBR Spring Forecast: headroom 23.6bn, GDP cut to 1.1%', 'Current-budget headroom ticks up from 22.0bn at the November Budget. 2026 growth downgraded from 1.4%. IMF subsequently cuts to 0.8% citing the Middle East shock.', 'fiscal', 'OBR EFO', 'https://obr.uk/efo/');
INSERT INTO timeline_events (id, event_date, title, summary, category, source_label, source_url) VALUES ('t_2026_02_28', '2026-02-28', 'Iran conflict begins, energy shock lands', 'UK natural gas front-month jumps 38% inside a week. 30y gilts break 5.5% for the first time since 1998. Tightrope Score moves from 51 to 68 over four trading sessions.', 'geopolitical', 'BoE markets', 'https://www.bankofengland.co.uk/markets');
INSERT INTO timeline_events (id, event_date, title, summary, category, source_label, source_url) VALUES ('t_2025_12_18', '2025-12-18', 'Planning & Infrastructure Bill receives Royal Assent', 'Landmark reform of the planning system passes both houses with cross-bench support; commencement orders expected by late spring.', 'delivery', 'Planning & Infrastructure Act 2025', 'https://www.legislation.gov.uk/ukpga/2025/34/enacted');
INSERT INTO timeline_events (id, event_date, title, summary, category, source_label, source_url) VALUES ('t_2026_02_12', '2026-02-12', 'BoE cuts Bank Rate to 3.75%', '7-2 vote. MPC minutes emphasise inflation persistence; markets trim the 2026 cut path.', 'monetary', 'BoE MPC minutes', 'https://www.bankofengland.co.uk/monetary-policy-summary-and-minutes');
INSERT INTO timeline_events (id, event_date, title, summary, category, source_label, source_url) VALUES ('t_2025_11', '2025-11-26', 'Autumn Budget: 22.0bn headroom restored', 'Combination of receipts upgrade and tighter departmental envelope rebuilds the cushion after the March 2025 crunch (9.9bn).', 'fiscal', 'HM Treasury', 'https://www.gov.uk/government/organisations/hm-treasury');
INSERT INTO timeline_events (id, event_date, title, summary, category, source_label, source_url) VALUES ('t_2025_09', '2025-09-18', 'BoE holds Bank Rate at 4.00%, starts reducing gilt sales', 'QT pace pared back; MPC cites technical market conditions rather than policy loosening.', 'monetary', 'BoE MPC minutes', 'https://www.bankofengland.co.uk/monetary-policy-summary-and-minutes');
INSERT INTO timeline_events (id, event_date, title, summary, category, source_label, source_url) VALUES ('t_2025_06', '2025-06-10', 'Industrial Strategy white paper published', 'Sets out eight priority sectors and the British Industrial Competitiveness Scheme framework.', 'policy', 'DBT', 'https://www.gov.uk/government/organisations/department-for-business-and-trade');
INSERT INTO timeline_events (id, event_date, title, summary, category, source_label, source_url) VALUES ('t_2025_03', '2025-03-26', 'OBR Spring Forecast: headroom collapses to 9.9bn', 'The crunch. Gilts reprice and the Chancellor promises restoration in the next fiscal event.', 'fiscal', 'OBR EFO', 'https://obr.uk/efo/');
INSERT INTO timeline_events (id, event_date, title, summary, category, source_label, source_url) VALUES ('t_2024_10', '2024-10-30', 'First Reeves Budget: 22.0bn headroom set', 'Opening fiscal envelope. Employer NICs rise, capital budgets reprioritised toward infrastructure.', 'fiscal', 'HM Treasury', 'https://www.gov.uk/government/organisations/hm-treasury');
INSERT INTO timeline_events (id, event_date, title, summary, category, source_label, source_url) VALUES ('t_2024_07_29', '2024-07-29', 'Reeves alleges 22bn fiscal black hole', 'Chancellor''s Public Spending Inheritance statement to the Commons claims an unfunded 22bn pressure on the 2024-25 fiscal envelope, sets up the trade-offs that frame the October Budget.', 'fiscal', 'HM Treasury', 'https://www.gov.uk/government/speeches/public-spending-inheritance');
INSERT INTO timeline_events (id, event_date, title, summary, category, source_label, source_url) VALUES ('t_2024_07_04', '2024-07-04', 'UK general election: Labour wins majority', 'Polls close on the 2024 UK general election. Labour returned with a majority of 174 seats; Keir Starmer takes office 5 July, Rachel Reeves becomes Chancellor — first fiscal event scheduled for late October.', 'fiscal', 'UK Parliament', 'https://members.parliament.uk/parties/Commons');
